import React, { useState, useRef, useEffect, useCallback } from 'react';
import ReactPlayer from 'react-player';
import YouTubePlayer from '../components/dictation/YouTubePlayer';
import { useParams, useNavigate } from 'react-router-dom';
import { dictationApi } from '../services/api';
import { calculateLevenshtein, analyzeWrongWords, getAccuracyBadge } from '../components/dictation/DictationHelpers';
import SpeechInput from '../components/dictation/SpeechInput';
import DictationSettingsModal from '../components/dictation/DictationSettingsModal';
import DictionaryTooltip from '../components/dictation/DictionaryTooltip';

const getFullMediaUrl = (url) => {
    if (!url) return '';
    if (url.startsWith('http') || url.startsWith('blob:') || url.startsWith('data:')) return url;

    const baseUrl = (import.meta.env.VITE_API_URL || 'http://localhost:3000/api').replace('/api', '');

    // Ensure baseUrl has a trailing slash and url doesn't have a leading slash
    const cleanBaseUrl = baseUrl.endsWith('/') ? baseUrl : `${baseUrl}/`;
    const cleanUrl = url.startsWith('/') ? url.substring(1) : url;

    // Convert to array of parts, encode each part, then join
    // This correctly handles spaces (%20) while preserving slashes (/)
    const encodedPath = cleanUrl.split('/').map(part => encodeURIComponent(part)).join('/');

    // Remove any unintended double slashes (except in http://)
    const finalUrl = `${cleanBaseUrl}${encodedPath}`.replace(/([^:]\/)\/+/g, "$1");

    return finalUrl;
};

const DictationPractice = () => {
    const { id: dictationId } = useParams();
    const navigate = useNavigate();

    // States
    const [dictation, setDictation] = useState(null);
    const [currentSentenceIndex, setCurrentSentenceIndex] = useState(0);

    // Step-by-step specific states
    const [userInputs, setUserInputs] = useState({}); // { [index]: string }
    const [sentenceResults, setSentenceResults] = useState({}); // { [index]: object }

    // Tabs & Learning Mode
    const [activeTab, setActiveTab] = useState('dictation'); // 'dictation', 'learning'
    const [currentTime, setCurrentTime] = useState(0);
    const [selectedWord, setSelectedWord] = useState(null);
    const [tooltipPosition, setTooltipPosition] = useState(null);
    const [isLooping, setIsLooping] = useState(false);

    // Shadowing states
    const [shadowingIndex, setShadowingIndex] = useState(null);
    const [shadowScores, setShadowScores] = useState({});
    const [isShadowRecording, setIsShadowRecording] = useState(false);
    const [shadowTranscript, setShadowTranscript] = useState('');

    // Blanks states
    const [blankConfigs, setBlankConfigs] = useState({});
    const [blankAnswers, setBlankAnswers] = useState({});
    const [showBlankHints, setShowBlankHints] = useState({});

    const sentenceListRef = useRef(null);

    // Derived values for current sentence
    const userInput = userInputs[currentSentenceIndex] || '';
    const currentResult = sentenceResults[currentSentenceIndex];
    const isSentenceCompleted = !!currentResult;

    const [showHint, setShowHint] = useState(false);
    const [revealedChars, setRevealedChars] = useState(0);
    const [showOriginal, setShowOriginal] = useState(false);

    // Settings
    const [showSettingsModal, setShowSettingsModal] = useState(false);
    const [settings, setSettings] = useState(() => {
        const savedSettings = localStorage.getItem('dictation_settings');
        return savedSettings ? JSON.parse(savedSettings) : {
            replayKey: 'Ctrl',
            autoReplay: '0', // '0', '1', '2', '3', '5', 'Infinity'
            replayDelay: 0.5, // seconds
            alwaysShowOriginal: false,
            alwaysShowHint: false
        };
    });

    // Save settings to local storage when changed
    useEffect(() => {
        localStorage.setItem('dictation_settings', JSON.stringify(settings));

        // Apply "Always show" settings immediately to current UI
        if (settings.alwaysShowOriginal) setShowOriginal(true);
        if (settings.alwaysShowHint) handleShowHint(true);
    }, [settings]);

    const [isPlaying, setIsPlaying] = useState(false);
    const [playbackRate, setPlaybackRate] = useState(1);
    const [isPlayerReady, setIsPlayerReady] = useState(false);
    const [hasStarted, setHasStarted] = useState(false); // NgÄƒn tá»± play lĂºc má»›i vĂ o

    // Auto Replay Logic
    const replayCountRef = useRef(0);
    const replayTimeoutRef = useRef(null);

    const [isRecording, setIsRecording] = useState(false);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [startTime, setStartTime] = useState(null);
    const [loading, setLoading] = useState(true);
    const [showSummary, setShowSummary] = useState(false);

    const playerRef = useRef(null);
    const inputRef = useRef(null);
    const resultsRef = useRef(null);

    // Load dictation data
    useEffect(() => {
        loadDictation();
    }, [dictationId]);

    // Set start time when user starts typing on a new sentence
    useEffect(() => {
        if (userInput && !startTime && !isSentenceCompleted) {
            setStartTime(Date.now());
        }
    }, [userInput, startTime, isSentenceCompleted]);

    // Auto scroll learning / blanks mode
    useEffect(() => {
        if ((activeTab === 'learning' || activeTab === 'blanks') && sentenceListRef.current) {
            const activeElement = sentenceListRef.current.querySelector(`[data-index="${currentSentenceIndex}"]`);
            if (activeElement) {
                // Check if scroll is needed
                activeElement.scrollIntoView({ behavior: 'smooth', block: 'center' });
            }
        }
    }, [currentSentenceIndex, activeTab]);

    const loadDictation = async () => {
        try {
            setLoading(true);
            const response = await dictationApi.getById(dictationId);
            setDictation(response.data);

            // Try to load saved progress from API, or local storage as fallback
            const savedStr = localStorage.getItem(`dictation_${dictationId}`);
            if (savedStr) {
                try {
                    const saved = JSON.parse(savedStr);
                    if (saved.userInputs) setUserInputs(saved.userInputs);
                    if (saved.sentenceResults) setSentenceResults(saved.sentenceResults);
                    if (saved.currentSentenceIndex !== undefined) setCurrentSentenceIndex(saved.currentSentenceIndex);
                } catch (e) {
                    console.error("Lá»—i parse local storage", e);
                }
            }
        } catch (error) {
            console.error('Error loading dictation:', error);
        } finally {
            setLoading(false);
        }
    };

    // Save progress to local storage on change
    useEffect(() => {
        if (Object.keys(sentenceResults).length > 0 || Object.keys(userInputs).length > 0) {
            localStorage.setItem(`dictation_${dictationId}`, JSON.stringify({
                userInputs,
                sentenceResults,
                currentSentenceIndex
            }));
        }
    }, [userInputs, sentenceResults, currentSentenceIndex, dictationId]);

    // Parse sentences from JSON
    const sentences = dictation
        ? (typeof dictation.sentences === 'string' ? JSON.parse(dictation.sentences) : dictation.sentences)
        : [];
    const currentSentence = sentences[currentSentenceIndex];

    useEffect(() => {
        if (sentences.length > 0 && dictation) {
            const vocab = Array.isArray(dictation.vocabulary) ? dictation.vocabulary.map(v => v.toLowerCase()) : [];
            const newConfigs = {};
            sentences.forEach((s, sIdx) => {
                const words = s.text.split(' ');
                const indicesToBlank = [];
                words.forEach((w, wIdx) => {
                    const clean = w.replace(/[.,!?"'`;:()[\]{}]/g, '').toLowerCase();
                    if (clean.length > 3 && vocab.includes(clean)) {
                        indicesToBlank.push(wIdx);
                    }
                });
                if (indicesToBlank.length === 0 && words.length > 3) {
                    let maxLen = 0; let maxIdx = 1;
                    words.forEach((w, wIdx) => {
                        const clean = w.replace(/[.,!?"'`;:()[\]{}]/g, '');
                        if (clean.length > maxLen) { maxLen = clean.length; maxIdx = wIdx; }
                    });
                    indicesToBlank.push(maxIdx);
                }
                newConfigs[sIdx] = indicesToBlank.slice(0, 2);
            });
            setBlankConfigs(newConfigs);
        }
    }, [dictation]); // Run when dictation loads

    let cleanAudioUrl = dictation?.audioUrl?.trim() || '';
    if (cleanAudioUrl) {
        try {
            const parsedUrl = new URL(cleanAudioUrl);
            parsedUrl.searchParams.delete('si');
            if (parsedUrl.hostname === 'youtu.be') {
                const videoId = parsedUrl.pathname.slice(1); // removes leading slash
                cleanAudioUrl = `https://www.youtube.com/watch?v=${videoId}`;
            } else {
                cleanAudioUrl = parsedUrl.toString();
            }
        } catch (e) {
            // ignore invalid url errors
        }
    }
    const audioUrlLower = cleanAudioUrl.toLowerCase();
    const isYouTubeUrl = audioUrlLower.includes('youtube.com') || audioUrlLower.includes('youtu.be');

    const replaySentence = useCallback((e, explicitSentence = null) => {
        const sentenceToPlay = explicitSentence || currentSentence;

        // Clear any pending replay timeout when user manually replays
        if (replayTimeoutRef.current) {
            clearTimeout(replayTimeoutRef.current);
            replayTimeoutRef.current = null;
        }

        if (sentenceToPlay && playerRef.current) {
            setHasStarted(true); // User explicitly triggered replay
            if (isYouTubeUrl) {
                if (isPlayerReady) {
                    playerRef.current.seekTo(sentenceToPlay.startTime, 'seconds');
                    if (playerRef.current.getInternalPlayer && typeof playerRef.current.getInternalPlayer().playVideo === 'function') {
                        playerRef.current.getInternalPlayer().playVideo();
                    }
                    setIsPlaying(true);
                }
            } else {
                playerRef.current.currentTime = sentenceToPlay.startTime;
                playerRef.current.play().catch(err => console.error("Play error:", err));
                setIsPlaying(true);
            }
        }
    }, [currentSentence, isYouTubeUrl, isPlayerReady]);

    // Handle sentence change - auto seek player and play
    useEffect(() => {
        if (!showSummary && sentences.length > 0) {
            // Stop any ongoing replay loops
            replayCountRef.current = 0;
            if (replayTimeoutRef.current) clearTimeout(replayTimeoutRef.current);

            // Chá»‰ tá»± play náº¿u ngÆ°á»i dĂ¹ng Ä‘Ă£ thá»±c hiá»‡n thao tĂ¡c start Ă­t nháº¥t 1 láº§n thay vĂ¬ tá»± play ngay lĂºc báº­t web
            if (hasStarted) {
                replaySentence();
            }

            if (!isSentenceCompleted) {
                // Keep cursor focus
                setTimeout(() => inputRef.current?.focus(), 100);
            }
            // Apply always show settings on new sentence
            if (settings.alwaysShowOriginal) setShowOriginal(true);
            else setShowOriginal(false);

            if (settings.alwaysShowHint) handleShowHint(true);
            else {
                setShowHint(false);
                setRevealedChars(0);
            }
        }
    }, [currentSentenceIndex, replaySentence, showSummary, isSentenceCompleted, sentences.length, settings, hasStarted]);

    // Centralized progress handler for both YouTube and Native Video
    const handleProgressCheck = (time) => {
        setCurrentTime(time);

        if (activeTab === 'blanks' && currentSentence) {
            const hasUnsolvedBlanks = blankConfigs[currentSentenceIndex]?.some(wIdx => {
                const clean = currentSentence.text.split(' ')[wIdx].replace(/[.,!?"'`;:()[\]{}]/g, '').toLowerCase();
                const ans = blankAnswers[currentSentenceIndex]?.[wIdx] || '';
                return ans.toLowerCase() !== clean;
            });

            if (time >= currentSentence.endTime && hasUnsolvedBlanks) {
                if (isYouTubeUrl && playerRef.current?.getInternalPlayer()?.pauseVideo) {
                    playerRef.current.getInternalPlayer().pauseVideo();
                    playerRef.current.seekTo(currentSentence.endTime - 0.5, 'seconds');
                } else if (!isYouTubeUrl && playerRef.current) {
                    playerRef.current.pause();
                    playerRef.current.currentTime = currentSentence.endTime - 0.5;
                }
                setIsPlaying(false);
                return; // Prevent normal progression until solved
            }
        }

        if ((activeTab === 'learning' || activeTab === 'blanks') && sentences.length > 0) {
            if (isLooping && currentSentence) {
                if (time >= currentSentence.endTime) {
                    if (isYouTubeUrl && playerRef.current) {
                        playerRef.current.seekTo(currentSentence.startTime, 'seconds');
                    } else if (!isYouTubeUrl && playerRef.current) {
                        playerRef.current.currentTime = currentSentence.startTime;
                    }
                    return;
                }
            }

            const activeIndex = sentences.findIndex(s => time >= s.startTime && time <= s.endTime);
            if (activeIndex !== -1 && activeIndex !== currentSentenceIndex) {
                setCurrentSentenceIndex(activeIndex);
                // Cancel any pending replays visually here since it moves on
            }
        }

        if (!currentSentence) return;

        if (activeTab === 'dictation') {
            if (time >= currentSentence.endTime && isPlaying) {
                setIsPlaying(false);

                // Pause player
                if (isYouTubeUrl && playerRef.current?.getInternalPlayer()?.pauseVideo) {
                    playerRef.current.getInternalPlayer().pauseVideo();
                } else if (!isYouTubeUrl && playerRef.current) {
                    playerRef.current.pause();
                }

                // Check auto replay settings
                if (settings.autoReplay !== "0" && !isSentenceCompleted) {
                    const maxReplays = settings.autoReplay === "Infinity" ? Infinity : parseInt(settings.autoReplay);

                    if (replayCountRef.current < maxReplays) {
                        replayCountRef.current += 1;

                        // Clear existing timeout
                        if (replayTimeoutRef.current) clearTimeout(replayTimeoutRef.current);

                        // Schedule next play
                        replayTimeoutRef.current = setTimeout(() => {
                            if (isYouTubeUrl && playerRef.current) {
                                playerRef.current.seekTo(currentSentence.startTime, 'seconds');
                                playerRef.current.getInternalPlayer()?.playVideo?.();
                            } else if (!isYouTubeUrl && playerRef.current) {
                                playerRef.current.currentTime = currentSentence.startTime;
                                playerRef.current.play().catch(e => console.error(e));
                            }
                            setIsPlaying(true);
                        }, settings.replayDelay * 1000);
                    }
                }
            }
        }
    };


    // Handle time update for native video
    const handleTimeUpdate = () => {
        if (!currentSentence || !playerRef.current || isYouTubeUrl) return;
        handleProgressCheck(playerRef.current.currentTime);
    };

    const handleUserInputChange = (val) => {
        if (isSentenceCompleted) return;
        setUserInputs(prev => ({ ...prev, [currentSentenceIndex]: val }));
    };

    // Keep submit logic in a ref to decouple dependencies in useEffect 
    const submitAttemptRef = useRef(null);
    const submitAttempt = async () => {
        if (!userInput.trim() || isSubmitting || isSentenceCompleted) return;

        setIsSubmitting(true);
        const timeSpent = startTime ? Math.round((Date.now() - startTime) / 1000) : 0;
        const correctText = currentSentence ? currentSentence.text : dictation.transcript;

        // Calculate metrics locally
        const levenshteinResult = calculateLevenshtein(userInput, correctText);
        const wrongWords = analyzeWrongWords(userInput, correctText);

        const localResults = {
            analysis: {
                ...levenshteinResult,
                wrongWords
            },
            correctTranscript: correctText,
            attempt: {
                userAnswer: userInput
            }
        };

        // Optimistic UI update
        setSentenceResults(prev => ({ ...prev, [currentSentenceIndex]: localResults }));

        // Cancel any pending replays
        if (replayTimeoutRef.current) clearTimeout(replayTimeoutRef.current);

        // Auto pause on complete depending on replay settings 
        // We pause immediately on submit even if auto replay is on, since user is done
        if (isPlaying || settings.autoReplay !== "0") {
            setIsPlaying(false);
            if (isYouTubeUrl && playerRef.current?.getInternalPlayer()?.pauseVideo) {
                playerRef.current.getInternalPlayer().pauseVideo();
            } else if (!isYouTubeUrl && playerRef.current) {
                playerRef.current.pause();
            }
        }

        try {
            await dictationApi.submit(dictationId, {
                userInput: userInput,
                originalText: correctText,
                timeSpent,
                accuracyScore: levenshteinResult.accuracy,
                levenshteinDist: levenshteinResult.distance,
                errorDetails: wrongWords
            });
            setTimeout(() => {
                resultsRef.current?.scrollIntoView({ behavior: 'smooth', block: 'end' });
            }, 100);
        } catch (error) {
            console.error('Error submitting:', error);
            setTimeout(() => {
                resultsRef.current?.scrollIntoView({ behavior: 'smooth', block: 'end' });
            }, 100);
        } finally {
            setIsSubmitting(false);
        }
    };
    submitAttemptRef.current = submitAttempt;

    // Use Auto Check logic separately
    const handleAutoCheck = useCallback(() => {
        if (!currentSentence || isSubmitting || isSentenceCompleted || !userInput) return;

        const cleanInput = userInput.trim().toLowerCase().replace(/[.,!?"'`;:()[\]{}]/g, '').replace(/\s+/g, ' ');
        const cleanCorrect = currentSentence.text.trim().toLowerCase().replace(/[.,!?"'`;:()[\]{}]/g, '').replace(/\s+/g, ' ');

        if (cleanInput === cleanCorrect && cleanInput.length > 0) {
            submitAttemptRef.current();
        }
    }, [userInput, currentSentence, isSubmitting, isSentenceCompleted]);

    useEffect(() => {
        handleAutoCheck();
    }, [handleAutoCheck]);

    const handleShadowSubmit = (index) => {
        if (!shadowTranscript.trim()) return;

        const originalText = sentences[index].text;
        const levenshteinResult = calculateLevenshtein(shadowTranscript, originalText);

        setShadowScores(prev => ({
            ...prev,
            [index]: {
                attempt: shadowTranscript,
                accuracy: levenshteinResult.accuracy,
                score: levenshteinResult.score
            }
        }));
        setShadowingIndex(null);
        setShadowTranscript('');
    };


    const handleNextSentenceRef = useRef(null);
    const handleNextSentence = () => {
        if (currentSentenceIndex < sentences.length - 1) {
            setCurrentSentenceIndex(prev => prev + 1);
            setStartTime(null);
            setRevealedChars(0);
            setShowHint(false);
            setShowOriginal(false);
            setHasStarted(true);
        } else {
            setShowSummary(true);
        }
    };
    handleNextSentenceRef.current = handleNextSentence;

    // Reset handler for current sentence
    const handleReset = () => {
        setUserInputs(prev => ({ ...prev, [currentSentenceIndex]: '' }));
        setSentenceResults(prev => {
            const newRes = { ...prev };
            delete newRes[currentSentenceIndex];
            return newRes;
        });
        if (!settings.alwaysShowHint) {
            setShowHint(false);
            setRevealedChars(0);
        }
        if (!settings.alwaysShowOriginal) setShowOriginal(false);
        setStartTime(Date.now());
        replayCountRef.current = 0;
        replaySentence();
        setTimeout(() => inputRef.current?.focus(), 100);
    };

    // Hint generator
    const handleShowHint = (isAuto = false) => {
        setShowHint(true);
        if (currentSentence) {
            const rawLength = currentSentence.text.replace(/[^a-zA-Z0-9]/g, '').length;
            if (isAuto && settings.alwaysShowHint) {
                // Do not increment chars if it's the auto initialization
                if (revealedChars === 0) setRevealedChars(1);
            } else if (revealedChars < rawLength) {
                setRevealedChars(prev => prev + 2); // Reveal 2 characters each click
            }
        }
    };

    const generateHintText = () => {
        if (!currentSentence) return '';
        const text = currentSentence.text;
        let revealedCount = 0;
        return text.split('').map((char) => {
            if (char === ' ' || /[.,!?]/.test(char)) return char;
            if (revealedCount < revealedChars) {
                revealedCount++;
                return char;
            }
            return '_';
        }).join(' ');
    };

    // Keyboard shortcuts
    useEffect(() => {
        const handleKeyDown = (e) => {

            // Check modifier key against settings
            const isModifierPressed =
                (settings.replayKey === 'Ctrl' && e.ctrlKey) ||
                (settings.replayKey === 'Shift' && e.shiftKey) ||
                (settings.replayKey === 'Alt' && e.altKey);

            if (isModifierPressed && (e.key === 'm' || e.key === 'M')) {
                e.preventDefault();
                setIsRecording(prev => !prev);
            }
            if (isModifierPressed && e.key === 'Enter') {
                e.preventDefault();
                if (!isSentenceCompleted) submitAttemptRef.current();
            }
            if (isModifierPressed && e.key === ' ') {
                e.preventDefault();
                setHasStarted(true);
                replayCountRef.current = 0; // manual replay resets auto loop
                replaySentence();
            }
            if (isModifierPressed && e.key === 'ArrowRight') {
                e.preventDefault();
                if (isSentenceCompleted) handleNextSentenceRef.current();
            }
        };

        window.addEventListener('keydown', handleKeyDown);
        return () => window.removeEventListener('keydown', handleKeyDown);
    }, [isSentenceCompleted, replaySentence, settings.replayKey]);

    // UI Helpers
    const getSentenceColor = (index) => {
        const res = sentenceResults[index];
        if (!res) {
            return index === currentSentenceIndex
                ? 'bg-blue-600 text-white shadow-md ring-2 ring-blue-300 transform scale-110'
                : 'bg-gray-100 text-gray-600 hover:bg-gray-200';
        }
        const acc = res.analysis.accuracy;
        if (acc >= 90) return index === currentSentenceIndex ? 'bg-green-600 text-white shadow-md ring-2 ring-green-300 transform scale-110' : 'bg-green-500 text-white hover:bg-green-600';
        if (acc >= 50) return index === currentSentenceIndex ? 'bg-yellow-500 text-white shadow-md ring-2 ring-yellow-300 transform scale-110' : 'bg-yellow-400 text-white hover:bg-yellow-500';
        return index === currentSentenceIndex ? 'bg-red-500 text-white shadow-md ring-2 ring-red-300 transform scale-110' : 'bg-red-400 text-white hover:bg-red-500';
    };

    if (loading) {
        return (
            <div className="flex items-center justify-center min-h-screen">
                <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-500"></div>
            </div>
        );
    }

    const handleWordClick = (word, e) => {
        e.stopPropagation();
        setSelectedWord(word);

        const rect = e.target.getBoundingClientRect();
        setTooltipPosition({
            x: rect.left + rect.width / 2,
            y: rect.top - 10
        });
    };

    if (!dictation) {
        return <div className="text-center p-8">KhĂ´ng tĂ¬m tháº¥y bĂ i Dictation</div>;
    }

    if (showSummary) {
        const resultsArray = Object.values(sentenceResults);
        const totalSentences = sentences.length;
        const completedCount = resultsArray.length;
        const averageAccuracy = completedCount > 0
            ? resultsArray.reduce((acc, curr) => acc + curr.analysis.accuracy, 0) / completedCount
            : 0;

        return (
            <div className="max-w-4xl mx-auto p-8 mt-10 bg-white rounded-3xl shadow-xl text-center border border-gray-100 animate-fade-in-up">
                <div className="text-7xl mb-6">đŸ†</div>
                <h2 className="text-3xl font-extrabold text-gray-800 mb-2">HoĂ n ThĂ nh BĂ i Táº­p!</h2>
                <p className="text-gray-500 mb-8 max-w-lg mx-auto leading-relaxed">{dictation.title}</p>

                <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-10">
                    <div className="p-6 bg-blue-50 bg-opacity-70 rounded-2xl border border-blue-100 hover:shadow-md transition">
                        <div className="text-sm font-medium text-blue-500 uppercase tracking-wider mb-2">Tiáº¿n Ä‘á»™</div>
                        <div className="text-4xl font-extrabold text-blue-700">{completedCount}<span className="text-2xl text-blue-400 font-medium">/{totalSentences}</span></div>
                    </div>
                    <div className="p-6 bg-green-50 bg-opacity-70 rounded-2xl border border-green-100 hover:shadow-md transition">
                        <div className="text-sm font-medium text-green-500 uppercase tracking-wider mb-2">Äá»™ chĂ­nh xĂ¡c</div>
                        <div className="text-4xl font-extrabold text-green-700">{averageAccuracy.toFixed(1)}%</div>
                    </div>
                    <div className="p-6 bg-purple-50 bg-opacity-70 rounded-2xl border border-purple-100 hover:shadow-md transition">
                        <div className="text-sm font-medium text-purple-500 uppercase tracking-wider mb-2">NgĂ´n ngá»¯</div>
                        <div className="text-4xl font-extrabold text-purple-700">{dictation.language}</div>
                    </div>
                </div>

                <div className="flex flex-col sm:flex-row justify-center items-center gap-4">
                    <button
                        onClick={() => {
                            setShowSummary(false);
                            setCurrentSentenceIndex(0);
                        }}
                        className="w-full sm:w-auto px-8 py-3.5 bg-gray-100 text-gray-700 font-bold rounded-xl hover:bg-gray-200 transition-colors shadow-sm"
                    >
                        Xem Láº¡i BĂ i LĂ m
                    </button>
                    <button
                        onClick={() => {
                            localStorage.removeItem(`dictation_${dictationId}`);
                            navigate('/dictation');
                        }}
                        className="w-full sm:w-auto px-8 py-3.5 bg-blue-600 text-white font-bold rounded-xl hover:bg-blue-700 transition-colors shadow-md shadow-blue-200"
                    >
                        Trá»Ÿ Vá» Danh SĂ¡ch
                    </button>
                </div>
            </div>
        );
    }

    return (
        <div className="max-w-7xl mx-auto p-4">
            {/* Header */}
